package fileutil

import (
	"bufio"
	"errors"
	"os"
	"strings"
)

type FileReader struct {
	file       *os.File
	bufferSize int
}

func NewFileReader(filePath string, bufferSize int) (*FileReader, error) {
	file, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}
	return &FileReader{
		file:       file,
		bufferSize: bufferSize,
	}, nil
}

func (fr *FileReader) ReadAllLines() ([]string, error) {
	var lines []string
	if fr.file == nil {
		return nil, errors.New("file handle is nil")
	}

	reader := bufio.NewReaderSize(fr.file, fr.bufferSize)
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			if errors.Is(err, os.ErrClosed) {
				return nil, errors.New("file lock encountered")
			}
			if err.Error() == "EOF" {
				break
			}
			return nil, errors.New("corrupted data or read error")
		}
		lines = append(lines, strings.TrimSpace(line))
	}

	return lines, nil
}

func (fr *FileReader) CloseHandle() error {
	if fr.file == nil {
		return errors.New("file handle is nil")
	}
	err := fr.file.Close()
	fr.file = nil
	return err
}

