import json
import csv
import xml.etree.ElementTree as ET
import asyncio
import time
import hashlib
from cryptography.fernet import Fernet

class DataTransformer:
    def __init__(self, ttl=300):
        self.processed_data_cache = {}
        self.ttl = ttl
        self.encryption_key = Fernet.generate_key()
        self.cipher = Fernet(self.encryption_key)

    async def convert_to_format(self, data, target_format, schema):
        validation_result = self.validate_input(data)
        if not validation_result:
            raise ValueError("Input data failed validation.")

        if target_format == "json":
            converted_data = json.dumps(data)
        elif target_format == "xml":
            root = ET.Element("root")
            for key, value in data.items():
                child = ET.SubElement(root, key)
                child.text = str(value)
            converted_data = ET.tostring(root).decode()
        elif target_format == "csv":
            output = csv.StringIO()
            writer = csv.writer(output)
            writer.writerow(data.keys())
            writer.writerow(data.values())
            converted_data = output.getvalue().strip()
        else:
            raise ValueError(f"Unsupported format: {target_format}")

        schema_validation_result = self.validate_schema(converted_data, schema)
        if not schema_validation_result:
            raise ValueError("Converted data failed schema validation.")

        encrypted_data = self.cipher.encrypt(converted_data.encode())
        await self.cache_processed_data(data, encrypted_data)
        return encrypted_data

    async def cache_processed_data(self, data, encrypted_data):
        cache_key = hashlib.sha256(json.dumps(data).encode()).hexdigest()
        self.processed_data_cache[cache_key] = {
            "data": encrypted_data,
            "timestamp": time.time()
        }

        # Remove expired cache entries
        expired_keys = []
        for key, value in self.processed_data_cache.items():
            if time.time() - value["timestamp"] > self.ttl:
                expired_keys.append(key)
        for key in expired_keys:
            del self.processed_data_cache[key]

    def validate_input(self, data):
        try:
            json.dumps(data).encode("utf-8")
            return True
        except UnicodeEncodeError:
            return False

    def validate_schema(self, data, schema):
        try:
            parsed_data = json.loads(data)
            return all(key in parsed_data for key in schema)
        except Exception:
            return False
