import protobuf from 'protobufjs';
import Ajv from 'ajv';

class WebSocketManager {
  constructor(config) {
    this.webSocket = null;
    this.config = config;
    this.heartbeatInterval = null;
    this.backoffTime = 1000; // Initial backoff time in ms
    this.subscriptions = new Map();
    this.messageSchemaValidator = new Ajv();
    this.connected = false;

    this.initializeWebSocket();
  }

  initializeWebSocket() {
    const { 'ws-url': wsUrl } = this.config;

    this.webSocket = new WebSocket(wsUrl);

    this.webSocket.onopen = () => this.onOpen();
    this.webSocket.onmessage = (event) => this.onMessage(event);
    this.webSocket.onerror = (error) => this.onError(error);
    this.webSocket.onclose = () => this.onClose();
  }

  onOpen() {
    this.connected = true;
    this.backoffTime = 1000; // Reset backoff time
    this.startHeartbeat();
    this.resubscribe();
  }

  onMessage(event) {
    const messageBuffer = event.data;
    protobuf.load('message.proto', (err, root) => {
      if (err) return;

      const Message = root.lookupType('Message');
      const decodedMessage = Message.decode(new Uint8Array(messageBuffer));

      if (this.validateMessage(decodedMessage)) {
        const { type, data } = decodedMessage;
        if (type && data && this.subscriptions.has(type)) {
          this.subscriptions.get(type).forEach((callback) => callback(data));
        }
      }
    });
  }

  validateMessage(message) {
    const valid = this.messageSchemaValidator.validate(this.config['json-schema'], message);
    if (!valid) {
      console.error('Invalid message payload', this.messageSchemaValidator.errors);
    }
    return valid;
  }

  subscribe(topic, callback) {
    if (!this.subscriptions.has(topic)) {
      this.subscriptions.set(topic, []);
    }
    this.subscriptions.get(topic).push(callback);

    if (this.connected) {
      this.sendMessage({ type: 'subscribe', topic });
    }
  }

  unsubscribe(topic) {
    if (this.subscriptions.has(topic)) {
      this.subscriptions.delete(topic);

      if (this.connected) {
        this.sendMessage({ type: 'unsubscribe', topic });
      }
    }
  }

  sendMessage(message) {
    if (!this.connected) return;

    protobuf.load('message.proto', (err, root) => {
      if (err) return;

      const Message = root.lookupType('Message');
      const buffer = Message.encode(Message.create(message)).finish();
      this.webSocket.send(buffer);
    });
  }

  resubscribe() {
    this.subscriptions.forEach((_, topic) => {
      this.sendMessage({ type: 'subscribe', topic });
    });
  }

  startHeartbeat() {
    const { 'heartbeat-interval': interval } = this.config;
    if (this.heartbeatInterval) clearInterval(this.heartbeatInterval);

    this.heartbeatInterval = setInterval(() => {
      this.sendMessage({ type: 'heartbeat' });
    }, interval);
  }

  stopHeartbeat() {
    clearInterval(this.heartbeatInterval);
    this.heartbeatInterval = null;
  }

  onError(error) {
    console.error('WebSocket error:', error);
  }

  onClose() {
    this.connected = false;
    this.stopHeartbeat();
    this.reconnectWithBackoff();
  }

  reconnectWithBackoff() {
    setTimeout(() => {
      this.initializeWebSocket();
      this.backoffTime = Math.min(this.backoffTime * 2, this.config['max-backoff'] || 30000);
    }, this.backoffTime + Math.random() * 1000);
  }
}

