class LogAnalyzer {
private:
    std::vector<std::string> logEntries;
    std::map<std::string, std::vector<std::string>> filteredEntries;

public:
    void parseLog(const std::string& filePath) {
        try {
            std::ifstream logFile(filePath);
            if (!logFile.is_open()) {
                throw std::runtime_error("Failed to open log file");
            }
            std::string line;
            while (std::getline(logFile, line)) {
                logEntries.push_back(line);
            }
            logFile.close();
        } catch (const std::exception& e) {
            std::cerr << "Error while parsing log: " << e.what() << std::endl;
            throw;
        }
    }

    void filterEntries(const std::string& severity) {
        try {
            filteredEntries[severity].clear();
            for (const std::string& entry : logEntries) {
                if (entry.find(severity) != std::string::npos) {
                    filteredEntries[severity].push_back(entry);
                }
            }
        } catch (const std::exception& e) {
            std::cerr << "Error while filtering entries: " << e.what() << std::endl;
            throw;
        }
    }

    void generateReport(const std::string& outputFilePath) {
        try {
            std::ofstream reportFile(outputFilePath);
            if (!reportFile.is_open()) {
                throw std::runtime_error("Failed to open report file");
            }
            for (const auto& [severity, entries] : filteredEntries) {
                reportFile << "Severity: " << severity << "\n";
                for (const std::string& entry : entries) {
                    reportFile << entry << "\n";
                }
                reportFile << "\n";
            }
            reportFile.close();
        } catch (const std::exception& e) {
            std::cerr << "Error while generating report: " << e.what() << std::endl;
            throw;
        }
    }
};

