    algorithm: CompressionAlgorithm,
}

impl FileCompressor {
    pub fn new(algorithm: CompressionAlgorithm) -> Self {
        FileCompressor { algorithm }
    }

    pub fn compress_file(&self, input_path: &Path, output_path: &Path) -> io::Result<()> {
        let input_file = Arc::new(Mutex::new(File::open(input_path)?));
        let mut output_file = File::create(output_path)?;

        match self.algorithm {
            CompressionAlgorithm::Gzip => {
                let encoder = GzEncoder::new(&mut output_file, flate2::Compression::default());
                let mut guard = input_file.lock().unwrap();
                io::copy(&mut *guard, &mut encoder)?;
            },
            CompressionAlgorithm::Bzip2 => {
                let encoder = BzEncoder::new(&mut output_file, bzip2::Compression::Default);
                let mut guard = input_file.lock().unwrap();
                io::copy(&mut *guard, &mut encoder)?;
            },
            CompressionAlgorithm::Lz4 => {
                let mut encoder = EncoderBuilder::new().build(&mut output_file)?;
                let mut guard = input_file.lock().unwrap();
                io::copy(&mut *guard, &mut encoder)?;
                let (_output, _result) = encoder.finish();
            },
        }

        Ok(())
    }

    pub fn decompress_file(&self, input_path: &Path, output_path: &Path) -> io::Result<()> {
        let input_file = Arc::new(Mutex::new(File::open(input_path)?));
        let mut output_file = File::create(output_path)?;

        match self.algorithm {
            CompressionAlgorithm::Gzip => {
                let mut decoder = GzDecoder::new(&mut *input_file.lock().unwrap());
                io::copy(&mut decoder, &mut output_file)?;
            },
            CompressionAlgorithm::Bzip2 => {
                let mut decoder = BzDecoder::new(&mut *input_file.lock().unwrap());
                io::copy(&mut decoder, &mut output_file)?;
            },
            CompressionAlgorithm::Lz4 => {
                let mut decoder = Decoder::new(&mut *input_file.lock().unwrap())?;
                io::copy(&mut decoder, &mut output_file)?;
            },
        }

        Ok(())
    }
