from sqlalchemy import create_engine

class DataPipeline:
    def __init__(self, database_url=None):
        self.database_url = database_url
        self.engine = create_engine(database_url) if database_url else None

    def extract_data(self, source, source_type='csv'):
        if source_type == 'csv':
            with open(source, mode='r') as file:
                reader = csv.DictReader(file)
                data = [row for row in reader]
        elif source_type == 'json':
            with open(source, mode='r') as file:
                data = json.load(file)
        elif source_type == 'database' and self.engine:
            with self.engine.connect() as connection:
                result = connection.execute(source)
                data = [dict(row) for row in result]
        else:
            raise ValueError('Unsupported source type or missing database configuration.')
        return data

    def transform_data(self, data, transformations):
        for transformation in transformations:
            data = transformation(data)
        return data

    def load_data(self, data, destination, destination_type='csv'):
        if destination_type == 'csv':
            with open(destination, mode='w', newline='') as file:
                writer = csv.DictWriter(file, fieldnames=data[0].keys())
                writer.writeheader()
                writer.writerows(data)
        elif destination_type == 'json':
            with open(destination, mode='w') as file:
                json.dump(data, file, indent=4)
        elif destination_type == 'database' and self.engine:
            with self.engine.connect() as connection:
                for row in data:
                    connection.execute(destination, **row)
        else:
            raise ValueError('Unsupported destination type or missing database configuration.')

    def run_pipeline(self, extract_args, transformations, load_args):
        extract_thread = threading.Thread(target=self.extract_data, args=extract_args)
        extract_thread.start()
        extract_thread.join()

        transform_thread = threading.Thread(target=self.transform_data, args=(extract_args,))
        transform_thread.start()
        transform_thread.join()

        load_thread = threading.Thread(target=self.load_data, args=load_args)
        load_thread.start()
        load_thread.join()

