type request_data struct {
	UserID    string
	AuthToken string
	Request   *http.Request
}

type rate_limiter struct {
	mu             sync.Mutex
	lastRequestMap map[string]time.Time
	limitDuration  time.Duration
}

func validate_request(req request_data) error {
	if req.UserID == "" || req.AuthToken == "" || req.Request == nil {
		return errors.New("invalid request data")
	}
	return nil
}

func limit_rate(limiter *rate_limiter, userID string) error {
	limiter.mu.Lock()
	defer limiter.mu.Unlock()

	lastRequestTime, exists := limiter.lastRequestMap[userID]
	if exists && time.Since(lastRequestTime) <= limiter.limitDuration {
		return errors.New("rate limit exceeded")
	}

	limiter.lastRequestMap[userID] = time.Now()
	return nil
}

func authenticate_user(req request_data, validTokens map[string]string) error {
	if token, ok := validTokens[req.UserID]; ok && token == req.AuthToken {
		return nil
	}
	return errors.New("authentication failed")
}

